public class TemplateMethod {
    static abstract class Report {
        final void generate() {
            header();
            body();
            footer();
        }
        void header() { System.out.println("=== Report ==="); }
        abstract void body();
        void footer() { System.out.println("=== End ==="); }
    }
    static class SalesReport extends Report {
        @Override void body() { System.out.println("Sales: $1000"); }
        @Override void footer() { System.out.println("Total: $1000"); }
    }
    public static void main(String[] args) {
        new SalesReport().generate();
    }
}
